        text: {
          maxCharacters: 2600,
        },
      },
    },
  },
}));

const preparedItems = $items('Preparar busquedas');
const exaItems = $input.all();

const departments = [
  'Ahuachapan',
  'Cabanas',
  'Chalatenango',
  'Cuscatlan',
  'La Libertad',
  'La Paz',
  'La Union',
  'Morazan',
  'San Miguel',
  'San Salvador',
  'San Vicente',
  'Santa Ana',
  'Sonsonate',
  'Usulutan',
];

const skillKeywords = [
  ['ventas', ['Ventas', 'Servicio al cliente']],
  ['cliente', ['Atencion al cliente', 'Comunicacion']],
  ['cajero', ['Caja', 'Atencion al cliente']],
  ['bodega', ['Inventario', 'Bodega']],
  ['almacen', ['Inventario', 'Bodega']],
  ['motorista', ['Licencia de conducir', 'Logistica']],
  ['repartidor', ['Logistica', 'Distribucion']],
  ['contabilidad', ['Contabilidad']],
  ['contador', ['Contabilidad']],
  ['administrativo', ['Administracion']],
  ['recursos humanos', ['Recursos humanos']],
  ['excel', ['Excel']],
  ['software', ['Software', 'Tecnologia']],
  ['sistemas', ['Sistemas', 'Tecnologia']],
  ['soporte tecnico', ['Soporte tecnico']],
  ['datos', ['Analisis de datos']],
  ['call center', ['Call center', 'Atencion al cliente']],
  ['ingles', ['Ingles']],
];

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function normalizeAscii(value) {
  return cleanText(value).normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function getResultText(result) {
  const highlights = Array.isArray(result.highlights) ? result.highlights.join('\n') : '';
  return [result.title, highlights, result.text].map(cleanText).filter(Boolean).join('\n');
}

function cleanTitle(title, provider) {
  return cleanText(title)
    .replace(/\s+\|\s+.*$/i, '')
    .replace(/\s+-\s+Computrabajo.*$/i, '')
    .replace(/\s+-\s+Tecoloco.*$/i, '')
    .replace(new RegExp('\\s+-\\s+' + provider + '.*$', 'i'), '')
    .trim();
}

function inferDepartment(text) {
  const normalizedText = normalizeAscii(text).toLowerCase();

  for (const department of departments) {
    if (normalizedText.includes(normalizeAscii(department).toLowerCase())) {
      return department;
    }
  }

  return '';
}

function inferSalary(text) {
  const normalized = cleanText(text);
  const matches = [...normalized.matchAll(/(?:US\$|\$)\s*([0-9]{3,5}(?:[.,][0-9]{2})?)|([0-9]{3,5}(?:[.,][0-9]{2})?)\s*(?:US\$|dolares|dolares)/gi)];
  const amounts = matches
    .map((match) => Number(String(match[1] || match[2]).replace(',', '.')))
    .filter((number) => Number.isFinite(number));

  if (amounts.length === 0) return { min: null, max: null };

  return {
    min: Math.min(...amounts),
    max: Math.max(...amounts),
  };
}

function parseDateFromText(text) {
  const normalized = cleanText(text);
  const iso = normalized.match(/\b\d{4}-\d{2}-\d{2}\b/);

  if (iso) return iso[0];

  const slash = normalized.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);

  if (slash) {
    const day = slash[1].padStart(2, '0');
    const month = slash[2].padStart(2, '0');
    return slash[3] + '-' + month + '-' + day;
  }

  return null;
}

function inferSkills(text) {
  const lower = normalizeAscii(text).toLowerCase();
  const skills = [];

  for (const [keyword, mappedSkills] of skillKeywords) {
    if (lower.includes(normalizeAscii(keyword).toLowerCase())) {
      skills.push(...mappedSkills);
    }
  }

  return unique(skills).slice(0, 14);
}

function inferModality(text) {
  const lower = normalizeAscii(text).toLowerCase();

  if (lower.includes('remoto') || lower.includes('remote')) return 'remoto';
  if (lower.includes('hibrido') || lower.includes('hybrid')) return 'hibrido';
  if (lower.includes('presencial')) return 'presencial';

  return '';
}

function inferEmploymentType(text) {
  const lower = normalizeAscii(text).toLowerCase();

  if (lower.includes('medio tiempo') || lower.includes('part time')) return 'medio tiempo';
  if (lower.includes('temporal')) return 'temporal';
  if (lower.includes('pasantia') || lower.includes('practica')) return 'pasantia';
  if (lower.includes('tiempo completo') || lower.includes('full time')) return 'tiempo completo';

  return '';
}

function isUsefulTitle(title) {
  const lower = normalizeAscii(title).toLowerCase();
  const generic = [
    'bolsa de trabajo',
    'portal de empleo',
    'buscar empleo',
    'consejos para encontrar empleo',
    'salarios',
    'evaluaciones de empresa',
  ];

  return title.length >= 4 && !generic.some((fragment) => lower.includes(fragment));
}

function normalizeResult(source, result) {
  const fullText = getResultText(result);
  const title = cleanTitle(result.title || result.url, source.provider);
  const salary = inferSalary(fullText);
  const department = inferDepartment(fullText);
  const description = cleanText(fullText).slice(0, 4200);

  return {
    source: source.source,
    external_id: result.url,
    provider: source.provider,
    title,
    company: '',
    area: source.area,
    description,
    employment_type: inferEmploymentType(fullText),
    modality: inferModality(fullText),
    country: 'El Salvador',
    department,
    municipality: '',
    location_text: department || 'El Salvador',
    salary_min: salary.min,
    salary_max: salary.max,
    currency: 'USD',
    expires_at: parseDateFromText(fullText),
    skills: inferSkills(fullText),
    source_url: result.url,
    apply_url: result.url,
    status: 'active',
    raw: {
      exa_id: result.id,
      published_date: result.publishedDate,
      query: source.query,
      score: result.score,
      highlights: result.highlights || [],
    },
  };
}

const outputs = [];
const seen = new Set();

for (let index = 0; index < exaItems.length; index += 1) {
  const prepared = preparedItems[index]?.json;
  const source = prepared?.source_config;

  if (!source) {
    throw new Error('No se encontro configuracion de fuente para el item ' + index + '.');
  }

  const exaData = exaItems[index].json || {};
  const results = Array.isArray(exaData.results) ? exaData.results : [];
  const jobs = [];

  for (const result of results) {
    if (!result?.url || !result?.title) continue;

    const key = source.source + '|' + result.url;
    if (seen.has(key)) continue;
    seen.add(key);

    const job = normalizeResult(source, result);
    if (!isUsefulTitle(job.title)) continue;

    jobs.push(job);
  }

  if (jobs.length === 0) {
    continue;
  }

  outputs.push({
    json: {
      source: source.source,
      result_count: results.length,
      job_count: jobs.length,
      trabajoya_base_url: prepared.trabajoya_base_url,
      trabajoya_api_key: prepared.trabajoya_api_key,
      payload: {
        source: source.source,
        sync: {
          provider: source.provider,
          query: source.query,
          include_domains: source.includeDomains,
          ran_at: new Date().toISOString(),
        },
        jobs,
      },
    },
  });
}

return outputs;
